package main

import "fmt"

type Media interface{ Title() string }

type Book struct{ TitleName string }
type Magazine struct{ TitleName string; Issue int }
type Audiobook struct{ TitleName, Narrator string }

func (b Book) Title() string       { return b.TitleName }
func (m Magazine) Title() string   { return m.TitleName }
func (a Audiobook) Title() string  { return a.TitleName }

func whatMedia(m Media) {
	switch v := m.(type) {
	case Book:
		fmt.Printf("Book: \"%s\"\n", v.TitleName)
	// TODO: add case Magazine
	case Audiobook:
		fmt.Printf("Audiobook: \"%s\" narrated by %s\n", v.TitleName, v.Narrator)
	default:
		fmt.Println("Unknown media type")
	}
}

func main() {
	whatMedia(Book{TitleName: "Clean Code"})
	whatMedia(Magazine{TitleName: "Time", Issue: 42})
	whatMedia(Audiobook{TitleName: "The Hobbit", Narrator: "Andy Serkis"})
}

