package main

import "fmt"

type Stockable interface {
	Stock(count int)
}

type Returnable interface {
	Return() string
}

type Borrowable interface {
	Stockable
	Returnable
}

type LibraryItem struct {
	Title string
	stock int
}

func (l *LibraryItem) Stock(count int) {
	l.stock = count
}

func (l *LibraryItem) Return() string {
	l.stock++
	return fmt.Sprintf("\"%s\" returned — %d copies available", l.Title, l.stock)
}

func processBorrow(b Borrowable, title string) {
	b.Stock(3)
	fmt.Println(b.Return())
}

func main() {
	item := &LibraryItem{Title: "The Art of War"}
	processBorrow(item, "The Art of War")
}

